selector_to_html = {"a[href=\"#create-rest-api\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Criar API REST<a class=\"headerlink\" href=\"#create-rest-api\" title=\"Link to this heading\">#</a></h2><h3>Breve Descri\u00e7\u00e3o<a class=\"headerlink\" href=\"#brief-description\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#request-mode\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Modo de Solicita\u00e7\u00e3o<a class=\"headerlink\" href=\"#request-mode\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#use-http-protocol-to-transfer-data\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Usar protocolo HTTP para transfer\u00eancia de dados<a class=\"headerlink\" href=\"#use-http-protocol-to-transfer-data\" title=\"Link to this heading\">#</a></h1><h2>Criar API REST<a class=\"headerlink\" href=\"#create-rest-api\" title=\"Link to this heading\">#</a></h2><h3>Breve Descri\u00e7\u00e3o<a class=\"headerlink\" href=\"#brief-description\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#set-the-content-type-of-the-scanner-request\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Defina o tipo de conte\u00fado do pedido do scanner<a class=\"headerlink\" href=\"#set-the-content-type-of-the-scanner-request\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#id2\"]": "<figure class=\"align-center\" id=\"id2\">\n<a class=\"reference internal image-reference\" href=\"../../Media/application-json.png\"><img alt=\"../../Media/application-json.png\" src=\"../../Media/application-json.png\" style=\"width: 300px;\"/>\n</a>\n<figcaption>\n<p><span class=\"caption-text\">Aplicativo/Json</span><a class=\"headerlink\" href=\"#id2\" title=\"Link to this image\">#</a></p>\n</figcaption>\n</figure>", "a[href=\"#request-url\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Solicitar URL<a class=\"headerlink\" href=\"#request-url\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#configure-scanner\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Configurar Scanner<a class=\"headerlink\" href=\"#configure-scanner\" title=\"Link to this heading\">#</a></h2><h3>Defina o tipo de conte\u00fado do pedido do scanner<a class=\"headerlink\" href=\"#set-the-content-type-of-the-scanner-request\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#return-parameter\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Par\u00e2metro de retorno<a class=\"headerlink\" href=\"#return-parameter\" title=\"Link to this heading\">#</a></h3><p>Para detalhes, consulte <a class=\"reference internal\" href=\"wireless.html#data-rceiving-format\"><span class=\"std std-ref\">Formato de recebimento de dados</span></a></p>", "a[href=\"#configure-wifi-and-api-url-address\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Configurar endere\u00e7o de URL do WiFi e API<a class=\"headerlink\" href=\"#configure-wifi-and-api-url-address\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#id3\"]": "<figure class=\"align-center\" id=\"id3\">\n<a class=\"reference internal image-reference\" href=\"../../Media/25WFCOMMPM23S1.png\"><img alt=\"../../Media/25WFCOMMPM23S1.png\" src=\"../../Media/25WFCOMMPM23S1.png\" style=\"width: 300px;\"/>\n</a>\n<figcaption>\n<p><span class=\"caption-text\">Json Format</span><a class=\"headerlink\" href=\"#id3\" title=\"Link to this image\">#</a></p>\n</figcaption>\n</figure>", "a[href=\"#set-the-data-format-sent-by-the-scanner\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Defina o formato de dados enviado pelo scanner<a class=\"headerlink\" href=\"#set-the-data-format-sent-by-the-scanner\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#id1\"]": "<div class=\"literal-block-wrapper docutils container\" id=\"id1\">\n<div class=\"code-block-caption\"><span class=\"caption-text\">Exemplo de solicita\u00e7\u00e3o</span><a class=\"headerlink\" href=\"#id1\" title=\"Link to this code\">#</a></div>\n<div class=\"highlight-json notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"linenos\">1</span><span class=\"p\">{</span><span class=\"nt\">\"id\"</span><span class=\"p\">:</span><span class=\"w\"> </span><span class=\"s2\">\"04B9023A\"</span><span class=\"p\">,</span><span class=\"nt\">\"msg\"</span><span class=\"p\">:</span><span class=\"s2\">\"1234567890\"</span><span class=\"p\">}</span>\n</pre></div>\n</div>\n</div>", "a[href=\"wireless.html#data-rceiving-format\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Formato de Coriving de Dados<a class=\"headerlink\" href=\"#data-rceiving-format\" title=\"Link to this heading\">#</a></h2><h3>C\u00f3digo de voz<a class=\"headerlink\" href=\"#voice-code\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#brief-description\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Breve Descri\u00e7\u00e3o<a class=\"headerlink\" href=\"#brief-description\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#request-parameters\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Par\u00e2metros de Requisi\u00e7\u00e3o<a class=\"headerlink\" href=\"#request-parameters\" title=\"Link to this heading\">#</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link", "sd-rounded-pill"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
